int f(int a) {
    return a * 2;
}

void example() {
    float (*p)(float) = (float (*)(float)) &f; // Noncompliant - illegal conversion
    void (*vp)() = (void (*)()) &f;           // Noncompliant - illegal conversion
}

// Another example of illegal conversion
