    return x + y;
}

void badExample() {
    int (*intFunc)(int, int) = (int (*)(int, int)) &calculate; // Noncompliant
}

compliant:
// Use proper function pointer types
int f(int a) {
    return a * 2;
}

void example() {
    int (*p)(int) = &f; // Compliant - correct type
    // Use std::function for type-erased storage if needed
    std::function<int(int)> func = f;
}

// Proper usage with matching signatures
double calculate(double x, double y) {
    return x + y;
}

void goodExample() {
    double (*doubleFunc)(double, double) = &calculate; // Compliant
}
